sql:
SELECT a.name
FROM athletes a
JOIN competition_results cr ON a.athlete_id = cr.athlete_id
WHERE cr.best_squat_kg = (
    SELECT MAX(best_squat_kg) FROM competition_results
);

SELECT COUNT(event_judges.event_id) AS total_events
FROM event_judges
WHERE judge_id = 1;

SELECT country, AVG(weight_kg) AS average_weight
FROM athletes
GROUP BY country;

SELECT COUNT(*) 
FROM event_notifications 
WHERE event_id = 'Specified Event ID';

SELECT athlete_id, COUNT(progress_id) as num_progress_entries
FROM athlete_progress
GROUP BY athlete_id;
